{
  "mode": "method",
  "tests": [
    {
      "name": "edit_scorecard_success",
      "input": {
        "project_id": "12345",
        "scorecard": {
          "rating": 4,
          "comments": "Good job!"
        }
      },
      "output": {
        "status": "success",
        "message": "Scorecard updated successfully."
      },
      "notes": "Validates that the scorecard can be edited and saved correctly."
    },
    {
      "name": "edit_scorecard_invalid_rating",
      "input": {
        "project_id": "12345",
        "scorecard": {
          "rating": 6,
          "comments": "Invalid rating."
        }
      },
      "output": {
        "status": "error",
        "message": "Rating must be between 1 and 5."
      },
      "notes": "Tests the system's response to an invalid rating input."
    },
    {
      "name": "edit_scorecard_no_comments",
      "input": {
        "project_id": "12345",
        "scorecard": {
          "rating": 3,
          "comments": ""
        }
      },
      "output": {
        "status": "success",
        "message": "Scorecard updated successfully."
      },
      "notes": "Checks if the scorecard can be saved without comments."
    },
    {
      "name": "edit_scorecard_multiple_tabs",
      "input": {
        "project_id": "12345",
        "scorecard": {
          "rating": 5,
          "comments": "Excellent work!"
        },
        "open_new_tab": true
      },
      "output": {
        "status": "success",
        "message": "Scorecard updated and project opened in a new tab."
      },
      "notes": "Validates that the project opens in a new tab after saving the scorecard."
    },
    {
      "name": "edit_scorecard_no_project_id",
      "input": {
        "scorecard": {
          "rating": 4,
          "comments": "Good effort!"
        }
      },
      "output": {
        "status": "error",
        "message": "Project ID is required."
      },
      "notes": "Tests the system's response when no project ID is provided."
    },
    {
      "name": "edit_scorecard_empty_input",
      "input": {
        "project_id": "12345",
        "scorecard": {}
      },
      "output": {
        "status": "error",
        "message": "Scorecard data is required."
      },
      "notes": "Checks the response when the scorecard input is empty."
    },
    {
      "name": "edit_scorecard_invalid_project_id",
      "input": {
        "project_id": "invalid_id",
        "scorecard": {
          "rating": 3,
          "comments": "Needs improvement."
        }
      },
      "output": {
        "status": "error",
        "message": "Invalid project ID."
      },
      "notes": "Tests the system's response to an invalid project ID."
    },
    {
      "name": "edit_scorecard_concurrent_edits",
      "input": {
        "project_id": "12345",
        "scorecard": {
          "rating": 2,
          "comments": "Needs more work."
        },
        "concurrent_edit": true
      },
      "output": {
        "status": "error",
        "message": "Concurrent edits detected. Please refresh."
      },
      "notes": "Validates the system's handling of concurrent edits to the scorecard."
    }
  ],
  "assumptions": "All inputs are properly formatted JSON objects.",
